import{c as e,Q as a,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const p=JSON.parse('{"title":"小白入门级 Harness 工程指南 — @freeman1266","description":"","frontmatter":{"title":"小白入门级 Harness 工程指南 — @freeman1266","author":"老金（@freeman1266）","date":"2026-05-11T00:00:00.000Z","source":"https://x.com/freeman1266/status/2053640630220517808","type":"tweet"},"headers":[],"relativePath":"research/tweets/2026-05-11-@freeman1266-517808.md","filePath":"research/tweets/2026-05-11-@freeman1266-517808.md","lastUpdated":1779894392000}'),s={name:"research/tweets/2026-05-11-@freeman1266-517808.md"};function l(n,t,i,d,u,h){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="小白入门级-harness-工程指南-—-freeman1266" tabindex="-1">小白入门级 Harness 工程指南 — @freeman1266 <a class="header-anchor" href="#小白入门级-harness-工程指南-—-freeman1266" aria-label="Permalink to &quot;小白入门级 Harness 工程指南 — @freeman1266&quot;">​</a></h1><p><strong>來源</strong>：<a href="https://x.com/freeman1266/status/2053640630220517808" target="_blank" rel="noreferrer">https://x.com/freeman1266/status/2053640630220517808</a><strong>作者</strong>：老金（@freeman1266） <strong>發布日期</strong>：2026-05-11 <strong>收錄日期</strong>：2026-05-11 <strong>類型</strong>：Twitter Article <strong>統計</strong>：24 likes · 3 retweets · 25 bookmarks · 1560 views</p><hr><h2 id="全文" tabindex="-1">全文 <a class="header-anchor" href="#全文" aria-label="Permalink to &quot;全文&quot;">​</a></h2><p>如果你用过 Claude Code、Cursor 或任何 AI Agent，一定遇到过这些瞬间：</p><ul><li>让它改 A 处的代码，它顺手把 B 处也改坏了。</li><li>多步任务执行到一半，它突然 &quot;忘了&quot; 前面说过的关键前提。</li><li>同一个问题，今天和昨天的回答 完全不同。</li><li>它说 &quot;我调用了 API&quot;，但你不知道它到底 传了什么参数。</li></ul><p>这些不是模型变笨了，而是模型本身就是这样的 —— 原始大模型的输出是随机的、无状态的、没有安全边界的。它再聪明，也只是一个 &quot;会说话的概率引擎&quot;。</p><p>要让它变成你能托付生产任务的工具，中间必须有一层 &quot;翻译官 + 守门人&quot;。</p><p>这一层就叫 Harness（驾驭工程）。</p><h2 id="一张图理解" tabindex="-1">一张图理解 <a class="header-anchor" href="#一张图理解" aria-label="Permalink to &quot;一张图理解&quot;">​</a></h2><p>模型不直接和你对话，也不直接动你的电脑。所有的输入输出，都要经过 Harness 这一层加工。</p><p>Claude Code 本身就是一个典型的 Harness —— 它包裹着 Claude 模型，决定模型能看到什么、能做什么、出错了怎么办。</p><h2 id="harness-做的三件事" tabindex="-1">Harness 做的三件事 <a class="header-anchor" href="#harness-做的三件事" aria-label="Permalink to &quot;Harness 做的三件事&quot;">​</a></h2><ol><li>决定 AI &quot;看到&quot;什么 —— 上下文管理</li></ol><p>模型的 &quot;记忆窗口&quot; 是有限的，塞得越满，反而越容易 &quot;迷失在中间&quot;（重要的信息被淹没）。</p><p>Harness 像一个资深副导演，负责筛选、压缩、排序：</p><ul><li>哪些历史对话还有用？哪些可以丢？</li><li>当前任务最相关的代码文件是哪几个？</li><li>工具返回的几千行日志，能不能只保留关键的几十行？</li></ul><blockquote><p>实例： 在 Claude Code 中，当长对话进行到一定程度，它会自动&quot;压缩历史&quot; —— 这就是 Harness 在腾出空间，把位置留给真正重要的推理线索。</p></blockquote><ol start="2"><li>决定 AI &quot;能做什么&quot; —— 动作拦截</li></ol><p>当模型说 &quot;我要写这个文件&quot; 或 &quot;我要执行这条命令&quot; 时，Harness 不会立刻照做。它会先拦下来检查：</p><ul><li>这个动作有权限吗？</li><li>会不会动到危险目录？</li><li>要不要先问一下用户？</li></ul><blockquote><p>实例： Claude 想运行一个新命令时弹出的 &quot;是否允许&quot; 提示 —— 这不是模型在问你，是 Harness 在问你。模型只是产生了 &quot;意图&quot;，是否变成 &quot;行动&quot;，由工程层决定。</p></blockquote><ol start="3"><li>决定 &quot;出错了怎么办&quot; —— 失败处理</li></ol><p>API 超时、命令报错、返回结果格式不对 —— 这些是 Agent 运行的常态，不是异常。</p><p>Harness 提供必要的兜底：</p><ul><li>命令失败：把报错信息打包回传给模型，让它自己想办法修。</li><li>反复失败：触发熔断，停下来报告，而不是越走越偏。</li><li>全程审计：每一步谁做了什么、结果如何，都留下可追溯的记录。</li></ul><blockquote><p>实例： Bash 命令超时或报错后，Claude Code 常常会自动换一种方式重试 —— 这套 &quot;重试 + 反馈&quot; 循环就是 Harness 实现的。</p></blockquote><h2 id="一句提醒-harness-不是免费的" tabindex="-1">一句提醒：Harness 不是免费的 <a class="header-anchor" href="#一句提醒-harness-不是免费的" aria-label="Permalink to &quot;一句提醒：Harness 不是免费的&quot;">​</a></h2><p>工程层不是银弹。它会增加系统复杂度、推高 Token 成本、引入额外延迟。</p><ul><li>做得太薄，系统不可用；</li><li>做得太厚，系统不智能。</li></ul><p>但对刚入门的你来说，先记住一件事就够了：</p><p>你和 AI Agent 打交道时感受到的 &quot;靠谱&quot; 或 &quot;不靠谱&quot;，很大程度不是模型的问题，而是 Harness 设计的问题。</p><p>你是否认同？或者有不同看法，欢迎评论区留下你的看法。</p><hr><h2 id="研究摘要" tabindex="-1">研究摘要 <a class="header-anchor" href="#研究摘要" aria-label="Permalink to &quot;研究摘要&quot;">​</a></h2><p><strong>TL;DR</strong>：Harness 是 AI Agent 的必要中間層（上下文管理+動作攔截+失敗兜底），決定系統「靠不靠谱」。</p><h3 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h3><ol><li>原始 LLM 是随机、无状态、无安全边界的概率引擎，不可直接用于生产</li><li>Harness = 翻译官 + 守门人，包裹模型決定能看什么、能做什么、出错怎办</li><li>三大職責：上下文管理（筛选压缩历史）、動作攔截（权限检查/用户确认）、失败处理（熔断+审计）</li><li>Claude Code 本身是 Harness 典型實例</li><li>Harness 有成本取捨：太薄不可用，太厚不智能</li></ol><h3 id="關鍵數據-工具" tabindex="-1">關鍵數據 / 工具 <a class="header-anchor" href="#關鍵數據-工具" aria-label="Permalink to &quot;關鍵數據 / 工具&quot;">​</a></h3><ul><li>Claude Code、Cursor（舉例工具）</li><li>概念：熔断（circuit breaker）、全程审计（audit trail）、上下文压缩（context compaction）</li></ul><h3 id="批判性觀察" tabindex="-1">批判性觀察 <a class="header-anchor" href="#批判性觀察" aria-label="Permalink to &quot;批判性觀察&quot;">​</a></h3><ol><li>概念正確但高度概括，三大職責是業界共識，無具體實作細節或設計取捨標準</li><li>讀者定位「小白入门」，與 SRE/架構師背景不符；Harness 概念在 cc-workspace 已有 <code>harness-design.md</code>、<code>harness-eval</code> skill 完整覆蓋</li><li>「AI 不靠谱 = Harness 設計問題」過度簡化，模型能力和 prompt 品質同樣關鍵</li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>說明</th></tr></thead><tbody><tr><td>A. Workspace 可行動性 (30%)</td><td>4/10</td><td>概念性介紹，無具體 prompt/hook/config；cc-workspace 已有完整 harness 文件，重疊度高</td></tr><tr><td>B. 創新性 (20%)</td><td>3/10</td><td>三大職責（context/action/error）是業界共識，Claude Code 舉例無新意</td></tr><tr><td>C. 證據品質 (20%)</td><td>2/10</td><td>無實驗數據、無 benchmark、全靠類比和現象描述</td></tr><tr><td>D. 技術深度 (15%)</td><td>3/10</td><td>提及熔断、审计等概念但均一句帶過，無實作細節</td></tr><tr><td>E. 泛化性 (15%)</td><td>6/10</td><td>Harness 概念本身跨工具通用，但文章以 Claude Code 為單一範例</td></tr><tr><td><strong>加權總分</strong></td><td><strong>3.55/10</strong></td><td>4×0.3+3×0.2+2×0.2+3×0.15+6×0.15 = 1.2+0.6+0.4+0.45+0.90</td></tr></tbody></table><p><strong>整合決策</strong>：Skip <strong>理由</strong>：總分 3.55，入門科普文，概念已被 cc-workspace 既有文件覆蓋，無增量價值</p>',46)])])}const q=e(s,[["render",l]]);export{p as __pageData,q as default};
